module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const size = parseFloat(args.size) || 2.6;
const align = args.align === 'left' ? 'left' : 'center';
const color = args.color ? `color:${args.color};` : '';
const weightMap = { light: '300', normal: '400', semibold: '600', bold: '700', heavy: '800' };
const weight = weightMap[String(args.weight || 'heavy').toLowerCase()] || '800';
const quote = String(args.quote) === 'true';
const mwRaw = parseFloat(args.maxwidth);
const mw = (Number.isFinite(mwRaw) && mwRaw > 0) ? mwRaw : 0;
let style = `--st-size:${size}rem; --st-weight:${weight}; text-align:${align}; ${color}`;
if (mw) { style += ` max-width:${mw}rem;`; if (align === 'center') style += ' margin-left:auto; margin-right:auto;'; }
let html = `\n\n<div class="mdp-mod-statement" style="${style}"><div class="mdp-st-body${quote ? ' is-quoted' : ''}">\n\n${content}\n\n</div>`;
if (args.by) html += `<div class="mdp-st-by">— ${esc(args.by)}</div>`;
html += `</div>\n\n`;
return html;
